'use client';

import React from 'react';
import { PieceType } from './types';
import { PIECES, BLOCK_SIZE } from './Constants';

interface BoxProps {
  label: string;
  pieceType: PieceType | null;
}

export const PieceBox: React.FC<BoxProps> = ({ label, pieceType }) => {
  return (
    <div className="flex flex-col items-center bg-gray-800 p-3 rounded-lg border-2 border-gray-600 min-w-[100px]">
      <span className="text-gray-400 text-xs font-bold uppercase mb-2">{label}</span>
      <div className="w-20 h-20 flex items-center justify-center bg-black rounded">
        {pieceType && (
          <div 
            className="grid" 
            style={{ 
              gridTemplateColumns: `repeat(${PIECES[pieceType].shape[0].length}, 1fr)`,
              gap: '1px'
            }}
          >
            {PIECES[pieceType].shape.map((row, y) => 
              row.map((val, x) => (
                <div 
                  key={`${x}-${y}`} 
                  className="w-4 h-4" 
                  style={{ backgroundColor: val ? PIECES[pieceType].color : 'transparent' }}
                />
              ))
            )}
          </div>
        )}
      </div>
    </div>
  );
};

interface StatsProps {
  score: number;
  level: number;
  lines: number;
}

export const GameStats: React.FC<StatsProps> = ({ score, level, lines }) => {
  return (
    <div className="flex flex-col gap-2 w-full">
      <div className="bg-gray-800 p-3 rounded-lg border-2 border-gray-600">
        <div className="text-gray-400 text-xs font-bold uppercase">Score</div>
        <div className="text-white text-xl font-mono">{score.toLocaleString()}</div>
      </div>
      <div className="bg-gray-800 p-3 rounded-lg border-2 border-gray-600">
        <div className="text-gray-400 text-xs font-bold uppercase">Level</div>
        <div className="text-white text-xl font-mono">{level}</div>
      </div>
      <div className="bg-gray-800 p-3 rounded-lg border-2 border-gray-600">
        <div className="text-gray-400 text-xs font-bold uppercase">Lines</div>
        <div className="text-white text-xl font-mono">{lines}</div>
      </div>
    </div>
  );
};
